CREATE TABLE IF NOT EXISTS "DigitalTwinCompany" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"baseline" JSONB NOT NULL,"assumptions" JSONB,"metrics" JSONB,"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","code"));
CREATE TABLE IF NOT EXISTS "DigitalTwinOrganization" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"companyId" TEXT NOT NULL REFERENCES "DigitalTwinCompany"("id") ON DELETE CASCADE ON UPDATE CASCADE,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"parentCode" TEXT,"structure" JSONB NOT NULL,"metrics" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("companyId","code"));
CREATE TABLE IF NOT EXISTS "DigitalTwinEmployee" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"companyId" TEXT NOT NULL REFERENCES "DigitalTwinCompany"("id") ON DELETE CASCADE ON UPDATE CASCADE,"employeeId" TEXT,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"department" TEXT,"position" TEXT,"skills" JSONB,"cost" DECIMAL(14,2),"capacity" DOUBLE PRECISION NOT NULL DEFAULT 1,"metrics" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("companyId","code"));
CREATE TABLE IF NOT EXISTS "DigitalTwinScenario" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"companyId" TEXT NOT NULL REFERENCES "DigitalTwinCompany"("id") ON DELETE CASCADE ON UPDATE CASCADE,"type" TEXT NOT NULL,"name" TEXT NOT NULL,"input" JSONB NOT NULL,"output" JSONB NOT NULL,"riskScore" DOUBLE PRECISION NOT NULL DEFAULT 0,"confidence" DOUBLE PRECISION NOT NULL DEFAULT 0,"recommendation" TEXT,"status" TEXT NOT NULL DEFAULT 'READY',"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "DecisionPolicy" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"entity" TEXT NOT NULL,"action" TEXT NOT NULL,"riskModel" JSONB,"fallback" TEXT NOT NULL DEFAULT 'HUMAN_APPROVAL',"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","code"));
CREATE TABLE IF NOT EXISTS "DecisionRule" ("id" TEXT NOT NULL PRIMARY KEY,"policyId" TEXT NOT NULL REFERENCES "DecisionPolicy"("id") ON DELETE CASCADE ON UPDATE CASCADE,"priority" INTEGER NOT NULL DEFAULT 100,"condition" JSONB NOT NULL,"outcome" JSONB NOT NULL,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "DecisionExecution" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"policyId" TEXT NOT NULL REFERENCES "DecisionPolicy"("id") ON DELETE CASCADE ON UPDATE CASCADE,"entityId" TEXT,"input" JSONB NOT NULL,"decision" TEXT NOT NULL,"riskScore" DOUBLE PRECISION NOT NULL,"confidence" DOUBLE PRECISION NOT NULL,"reason" TEXT NOT NULL,"fallbackRequired" BOOLEAN NOT NULL DEFAULT false,"approvedById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "KnowledgeCategory" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","code"));
CREATE TABLE IF NOT EXISTS "KnowledgeNode" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"categoryId" TEXT REFERENCES "KnowledgeCategory"("id") ON DELETE SET NULL ON UPDATE CASCADE,"type" TEXT NOT NULL,"entityId" TEXT,"label" TEXT NOT NULL,"content" TEXT,"vector" JSONB,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "KnowledgeRelation" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"fromNodeId" TEXT NOT NULL REFERENCES "KnowledgeNode"("id") ON DELETE CASCADE ON UPDATE CASCADE,"toNodeId" TEXT NOT NULL REFERENCES "KnowledgeNode"("id") ON DELETE CASCADE ON UPDATE CASCADE,"type" TEXT NOT NULL,"weight" DOUBLE PRECISION NOT NULL DEFAULT 1,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "GlobalSearchDocument" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"entity" TEXT NOT NULL,"entityId" TEXT NOT NULL,"title" TEXT NOT NULL,"content" TEXT NOT NULL,"locale" TEXT,"url" TEXT,"vector" JSONB,"ocrText" TEXT,"facets" JSONB,"permissions" JSONB,"rank" DOUBLE PRECISION NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","entity","entityId"));
CREATE TABLE IF NOT EXISTS "AIAssistantConversation" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"userId" TEXT,"title" TEXT NOT NULL,"context" JSONB,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "AIAssistantMessage" ("id" TEXT NOT NULL PRIMARY KEY,"conversationId" TEXT NOT NULL REFERENCES "AIAssistantConversation"("id") ON DELETE CASCADE ON UPDATE CASCADE,"role" TEXT NOT NULL,"content" TEXT NOT NULL,"toolCalls" JSONB,"output" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "AIAssistantMemory" ("id" TEXT NOT NULL PRIMARY KEY,"conversationId" TEXT REFERENCES "AIAssistantConversation"("id") ON DELETE CASCADE ON UPDATE CASCADE,"tenantId" TEXT,"userId" TEXT,"key" TEXT NOT NULL,"value" JSONB NOT NULL,"expiresAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "LowCodeArtifact" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"type" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"schema" JSONB NOT NULL,"version" INTEGER NOT NULL DEFAULT 1,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","type","code"));
CREATE TABLE IF NOT EXISTS "ProcessMiningEvent" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"processKey" TEXT NOT NULL,"caseId" TEXT NOT NULL,"activity" TEXT NOT NULL,"actorId" TEXT,"startedAt" TIMESTAMP(3) NOT NULL,"finishedAt" TIMESTAMP(3),"durationMs" INTEGER,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ProcessMiningInsight" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"processKey" TEXT NOT NULL,"type" TEXT NOT NULL,"title" TEXT NOT NULL,"metrics" JSONB NOT NULL,"recommendation" TEXT,"severity" TEXT NOT NULL DEFAULT 'INFO',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "DataFabricAsset" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"domain" TEXT NOT NULL,"name" TEXT NOT NULL,"assetType" TEXT NOT NULL,"metadata" JSONB NOT NULL,"lineage" JSONB,"quality" JSONB,"masterKey" TEXT,"ownerId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "PredictiveModel" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"type" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"features" JSONB NOT NULL,"parameters" JSONB,"status" TEXT NOT NULL DEFAULT 'READY',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","type","code"));
CREATE TABLE IF NOT EXISTS "PredictiveRun" ("id" TEXT NOT NULL PRIMARY KEY,"modelId" TEXT NOT NULL REFERENCES "PredictiveModel"("id") ON DELETE CASCADE ON UPDATE CASCADE,"input" JSONB NOT NULL,"output" JSONB NOT NULL,"confidence" DOUBLE PRECISION NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "GenerativeReport" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"type" TEXT NOT NULL,"title" TEXT NOT NULL,"prompt" TEXT NOT NULL,"format" TEXT NOT NULL,"content" JSONB NOT NULL,"fileUrl" TEXT,"status" TEXT NOT NULL DEFAULT 'GENERATED',"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ObservabilitySpan" ("id" TEXT NOT NULL PRIMARY KEY,"traceId" TEXT NOT NULL,"spanId" TEXT NOT NULL,"parentSpanId" TEXT,"service" TEXT NOT NULL,"operation" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'OK',"durationMs" INTEGER NOT NULL,"attributes" JSONB,"startedAt" TIMESTAMP(3) NOT NULL,"endedAt" TIMESTAMP(3));
CREATE TABLE IF NOT EXISTS "EdgeSyncRecord" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"deviceId" TEXT NOT NULL,"entity" TEXT NOT NULL,"entityId" TEXT NOT NULL,"operation" TEXT NOT NULL,"payload" JSONB NOT NULL,"status" TEXT NOT NULL DEFAULT 'PENDING',"conflict" JSONB,"syncedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "MultiRegionConfig" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"region" TEXT NOT NULL,"role" TEXT NOT NULL,"endpoint" TEXT NOT NULL,"geoRouting" JSONB,"replication" JSONB,"drPolicy" JSONB,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","region","role"));
CREATE TABLE IF NOT EXISTS "ZeroTrustPolicy" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"policyType" TEXT NOT NULL,"conditions" JSONB NOT NULL,"actions" JSONB NOT NULL,"riskThreshold" DOUBLE PRECISION NOT NULL DEFAULT 0.5,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","code"));
